def possible_winner_sets(n):
    runners = list(range(2**n))
    sets = set()
    # generate all perfect matchings
    # use partitions into pairs
    def pairings(lst):
        if not lst:
            yield []
            return
        first = lst[0]
        for i in range(1, len(lst)):
            second = lst[i]
            rest = lst[1:i] + lst[i+1:]
            for p in pairings(rest):
