def v2(x):
    if x==0: return None
    c=0
    while x%2==0:
        x//=2
        c+=1
    return c

def sum_series(p, k, m):
    # sum_{i=0}^{m} p^{k*i}
    s=0
    for i in range(m+1):
        s += p**(k*i)
    return s

for p in [3,5,7,11,13]:
