def f_original(n, exponent=2):
    total = 0
    for i in range(1, n+1):
        for j in range(1, n+1):
            total += (j**exponent) * ((1/j + (n-i)/n)//1)  # floor
    return total

def f_simplified(n, exponent=2):
    total = 0
    for j in range(1, n+1):
        total += (j**exponent) * (n//j)
    return total

for n in range(1, 10):
    print(n, f_original(n, 2), f_simplified(n, 2))

def f_diff(A, exponent=2):
